`,r.jsxs(e.li,{children:[r.jsx(e.strong,{children:"CSS Selectors"}),": Find elements by using CSS classes or rules (e.g., ",r.jsx(e.code,{children:".your-class-name"}),")"]}),`
`,r.jsxs(e.li,{children:[r.jsx(e.strong,{children:"Element Selectors"}),": Find elements inside the elements (e.g., ",r.jsx(e.code,{children:"#\\@\\@blui-drawerlayout-content > div > header > div > button"}),")"]}),`
